    if (group) {
      group.push(t);
    } else {
      map.set(key, [t]);
    }
  }

  const duplicateGroups: DuplicateGroup[] = [];
  for (const [key, txns] of map) {
    if (txns.length >= 2) {
      duplicateGroups.push({ key, transactions: txns });
    }
  }

  return duplicateGroups;
}

/**
 * Calculates running balance for a specific user, sorted by date.
 * O(n log n): single filter + sort, then one linear pass for accumulation.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  const userTransactions = transactions
    .filter((t) => t.userId === userId)
    .sort((a, b) => a.date.localeCompare(b.date));

  const entries: RunningBalanceEntry[] = [];
  let balance = 0;

  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}

/**
 * Returns the top N spenders.
 * O(n) to build totals map, O(u log u) to sort unique users — no bubble sort.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const existing = map.get(t.userId);
    if (existing) {
      existing.total += t.amount;
      existing.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  // Native sort (O(u log u)) instead of bubble sort (O(u^2))
  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 * Compiles RegExp once before the loop; uses Set for O(1) dedup.
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  // Compile once instead of on every iteration
  const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
  const seen = new Set<string>();
  const results: Transaction[] = [];

  for (const transaction of transactions) {
    if (pattern.test(transaction.description) && !seen.has(transaction.id)) {
      seen.add(transaction.id);
      results.push(transaction);
    }
  }

  return results;
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

